import{_ as s,c as a,o as e,a as n}from"./app.09261a68.js";const A=JSON.parse('{"title":"NFS Server","description":"","frontmatter":{"date":"2022-11-24T00:00:00.000Z"},"headers":[{"level":2,"title":"概览","slug":"概览","link":"#概览","children":[]},{"level":2,"title":"环境说明","slug":"环境说明","link":"#环境说明","children":[]},{"level":2,"title":"安装NFS Server","slug":"安装nfs-server","link":"#安装nfs-server","children":[]},{"level":2,"title":"配置NFS Server","slug":"配置nfs-server","link":"#配置nfs-server","children":[]},{"level":2,"title":"配置共享目录","slug":"配置共享目录","link":"#配置共享目录","children":[]},{"level":2,"title":"重启 NFS Server","slug":"重启-nfs-server","link":"#重启-nfs-server","children":[]}],"relativePath":"zh/tools/nfs-server.md"}'),l={name:"zh/tools/nfs-server.md"},t=n(`<h1 id="nfs-server" tabindex="-1">NFS Server <a class="header-anchor" href="#nfs-server" aria-hidden="true">#</a></h1><h2 id="概览" tabindex="-1">概览 <a class="header-anchor" href="#概览" aria-hidden="true">#</a></h2><p>NFS Server管理一个或多个文件目录，使得这些文件目录可以被挂载到多台服务器上，成为多台服务器共享的文件目录。</p><h2 id="环境说明" tabindex="-1">环境说明 <a class="header-anchor" href="#环境说明" aria-hidden="true">#</a></h2><p>通过如下指令查看系统环境：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#A6ACCD;">$ cat /etc/redhat-release </span></span>
<span class="line"><span style="color:#A6ACCD;">CentOS Linux release 7.9.2009 (Core)</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span></code></pre></div><h2 id="安装nfs-server" tabindex="-1">安装NFS Server <a class="header-anchor" href="#安装nfs-server" aria-hidden="true">#</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#A6ACCD;">$ sudo yum install nfs-utils</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span></code></pre></div><p>只安装 nfs-utils 即可，rpcbind 属于它的依赖，也会安装上。</p><h2 id="配置nfs-server" tabindex="-1">配置NFS Server <a class="header-anchor" href="#配置nfs-server" aria-hidden="true">#</a></h2><ol><li><p>设置 NFS 服务开机启动</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#A6ACCD;">$ sudo systemctl enable rpcbind</span></span>
<span class="line"><span style="color:#A6ACCD;">$ sudo systemctl enable nfs</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span></code></pre></div></li><li><p>启动 NFS 服务</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#A6ACCD;">$ sudo systemctl start rpcbind</span></span>
<span class="line"><span style="color:#A6ACCD;">$ sudo systemctl start nfs</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span></code></pre></div></li><li><p>打开防火墙 rpc-bind 和 nfs 的服务 如果防火墙未开启，则可以跳过此步骤：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#A6ACCD;">$ sudo firewall-cmd --zone=public --permanent --add-service={rpc-bind,mountd,nfs}</span></span>
<span class="line"><span style="color:#A6ACCD;">success</span></span>
<span class="line"><span style="color:#A6ACCD;">$ sudo firewall-cmd --reload</span></span>
<span class="line"><span style="color:#A6ACCD;">success</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span></code></pre></div></li></ol><h2 id="配置共享目录" tabindex="-1">配置共享目录 <a class="header-anchor" href="#配置共享目录" aria-hidden="true">#</a></h2><ol><li>创建在服务器之间共享的目录</li></ol><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#A6ACCD;">$ sudo mkdir -p /home/nfs/data</span></span>
<span class="line"><span style="color:#A6ACCD;">$ sudo chmod 755 /home/nfs/data</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span></code></pre></div><ol start="2"><li><p>导出相应配置目录</p><ul><li>编辑导出文件：</li></ul><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#A6ACCD;">$ sudo vi /etc/exports</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span></code></pre></div><ul><li>添加如下配置</li></ul><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#A6ACCD;">/home/nfs/data/     192.168.1.0/24(rw,sync,no_root_squash,no_all_squash)</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span></code></pre></div><ul><li><p>配置说明：</p><ul><li><code>/data</code>: 共享目录位置。</li><li><code>192.168.1.0/24</code>: 客户端 IP 范围，<code>*</code> 代表所有，即没有限制。</li><li><code>rw</code>: 权限设置，可读可写。</li><li><code>sync</code>: 同步共享目录。</li><li><code>no_root_squash</code>: 可以使用 root 授权。</li><li><code>no_all_squash</code>: 可以使用普通用户授权。</li></ul></li></ul></li></ol><h2 id="重启-nfs-server" tabindex="-1">重启 NFS Server <a class="header-anchor" href="#重启-nfs-server" aria-hidden="true">#</a></h2><p>重启NFS Server:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#A6ACCD;">$ sudo systemctl restart nfs</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span></code></pre></div><p>检查一下本地的共享目录:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#A6ACCD;">$ showmount -e localhost</span></span>
<span class="line"><span style="color:#A6ACCD;">Export list for localhost:</span></span>
<span class="line"><span style="color:#A6ACCD;">/home/nfs/data 192.168.1.0/24</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span></code></pre></div><p>这样，服务端就配置好了，接下来配置客户端，连接服务端，使用共享目录。</p>`,21),p=[t];function o(i,c,r,d,h,C){return e(),a("div",null,p)}const v=s(l,[["render",o]]);export{A as __pageData,v as default};
